"""A shopping cart with item management and discount support."""

from __future__ import annotations

from dataclasses import dataclass
from decimal import Decimal
from enum import Enum


class CartError(Exception):
    """Base exception for all shopping cart errors."""


class ProductNotFoundError(CartError):
    """Raised when an operation references a product not present in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(f"No item with product name {product_name!r} exists in the cart.")
        self.product_name = product_name


class DuplicateProductError(CartError):
    """Raised when adding a product that is already in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(
            f"Item {product_name!r} is already in the cart; "
            f"update its quantity instead of adding it again."
        )
        self.product_name = product_name


class InvalidQuantityError(CartError):
    """Raised when a quantity is not a positive integer."""

    def __init__(self, quantity: int) -> None:
        super().__init__(f"Quantity must be a positive integer, got {quantity!r}.")
        self.quantity = quantity


class InvalidPriceError(CartError):
    """Raised when a unit price is negative."""

    def __init__(self, unit_price: Decimal) -> None:
        super().__init__(f"Unit price must not be negative, got {unit_price!r}.")
        self.unit_price = unit_price


class InvalidDiscountError(CartError):
    """Raised when a discount amount is invalid for its discount type."""

    def __init__(self, message: str) -> None:
        super().__init__(message)


class DiscountType(Enum):
    """Supported ways of reducing the cart subtotal."""

    PERCENTAGE = "percentage"
    FLAT = "flat"


@dataclass(frozen=True)
class CartItem:
    """An immutable line item: a product, its unit price, and its quantity."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def line_total(self) -> Decimal:
        """Return the cost of this line (unit price multiplied by quantity)."""
        return self.unit_price * self.quantity


@dataclass(frozen=True)
class Discount:
    """A discount to apply to the cart subtotal."""

    discount_type: DiscountType
    amount: Decimal

    def apply_to(self, subtotal: Decimal) -> Decimal:
        """Return the discounted subtotal, never falling below zero."""
        if self.discount_type is DiscountType.PERCENTAGE:
            reduction = subtotal * (self.amount / Decimal(100))
        else:
            reduction = self.amount
        return max(Decimal(0), subtotal - reduction)


class ShoppingCart:
    """An in-memory shopping cart supporting item management and a single discount.

    Items are keyed by product name, so each product appears at most once. Prices
    are handled with :class:`~decimal.Decimal` to avoid floating-point rounding
    errors in monetary calculations.
    """

